import{_ as o,o as d,c as t,a3 as c}from"./chunks/framework.BlfGB29P.js";const g=JSON.parse('{"title":"权限模型","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/permissions.md","filePath":"cosmos/basic-app/permissions.md","lastUpdated":1783300196000}'),s={name:"cosmos/basic-app/permissions.md"};function a(n,e,r,i,l,p){return d(),t("div",null,[...e[0]||(e[0]=[c(`<h1 id="权限模型" tabindex="-1">权限模型 <a class="header-anchor" href="#权限模型" aria-label="Permalink to &quot;权限模型&quot;">​</a></h1><p>XiHan.BasicApp 的权限体系融合 <strong>RBAC（基于角色）</strong> 与 <strong>ABAC（基于属性）</strong>，再叠加<strong>角色继承、数据范围、字段级脱敏、多租户版本门控</strong>。这是系统最核心也最需要理解的部分——一次请求要穿过认证、租户解析、权限码、约束、数据范围、字段脱敏六道关卡，每一道都可能收窄或拒绝。</p><p>权限相关的领域实体几乎全部集中在 <code>modules/XiHan.BasicApp.Saas/Domain/Entities/</code>（<code>Sys*</code>），运行时判定由框架 <a href="./../framework/packages/authorization">授权模块</a> 承接。本页以真实源码为准，讲清&quot;怎么用、为什么这么设计、怎么扩展&quot;。</p><h2 id="权限码-单一事实源" tabindex="-1">权限码：单一事实源 <a class="header-anchor" href="#权限码-单一事实源" aria-label="Permalink to &quot;权限码：单一事实源&quot;">​</a></h2><p>权限的基本单位是<strong>权限码</strong>，格式固定为三段：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module : resource : action</span></span>
<span class="line"><span>模块     资源       动作</span></span></code></pre></div><ul><li>例：<code>saas:user:read</code>（读取用户）、<code>saas:role:export</code>（导出角色）、<code>saas:permission:create</code>（创建权限定义）</li><li>超级管理员在授权快照里持有<strong>字面通配 <code>*</code></strong>，放行一切。注意：匹配是&quot;命中 <code>*</code> 或精确等于该权限码&quot;（大小写不敏感），<strong>不支持</strong> <code>resource:*:*</code> 之类的段级通配——通配仅有 <code>*</code> 这一个特例，见下文判定链</li></ul><blockquote><p>冒号分三段是硬约定：<code>SaasPermissionDefinitions.ResolveGroupCode</code> 按 <code>saas:{resource}:{action}</code> 取中间段作为<strong>分组码</strong>（资源段），前端权限中心据此把权限归类展示。</p></blockquote><p>所有 SaaS 权限码的<strong>唯一手写源</strong>是 <code>Domain/Permissions/SaasPermissionCodes.cs</code>（常量）与 <code>Domain/Permissions/SaasPermissionDefinitions.cs</code>（分组 + 元数据）：</p><ul><li><code>SaasPermissionCodes</code> 按资源分嵌套静态类，每个动作一个 <code>const string</code>，如 <code>SaasPermissionCodes.User.Read = &quot;saas:user:read&quot;</code>。后端 <code>[PermissionAuthorize(SaasPermissionCodes.User.Read)]</code> 直接引用常量，杜绝魔法字符串。</li><li><code>SaasPermissionDefinitions.Groups</code> 是<strong>手写单一事实源</strong>：每个资源块一个 <code>SaasPermissionGroup</code>（组码 + 中文组名 + 组内 <code>SaasPermissionItem</code> 列表）。落库扁平表 <code>All</code>、组码→组名 <code>GroupNames</code> 全由 <code>Groups</code> 派生，每条权限的 <code>ModuleCode</code>（恒为 <code>saas</code>）、<code>Tags</code>、<code>Priority</code>（恒等于 <code>Sort</code>）自动生成，无需手写。</li><li>新增资源时只在 <code>Groups</code> 增一个分组节点、或在已有节点增一条权限项即可，种子据此落库。</li></ul><p>每条权限项携带一个关键标志 <code>IsRequireAudit</code>：为 <code>true</code> 时，该权限对应的操作应强制写差异日志（<code>SysDiffLog</code>），用于合规审计。写类动作（create/update/delete/grant/revoke）多为 <code>true</code>，读与导出多为 <code>false</code>。</p><h3 id="三级门控" tabindex="-1">三级门控 <a class="header-anchor" href="#三级门控" aria-label="Permalink to &quot;三级门控&quot;">​</a></h3><p>前端页面、字段、操作三级都按权限码过滤——没有对应权限码，元素<strong>不渲染 / 不可操作</strong>。菜单本身由后端 <code>PageRegistry</code> 单一事实源注册并绑定权限码（建菜单即绑权限），前端据此渲染可见菜单树；页面内的按钮/操作与列表字段再按权限码与字段级安全策略二次过滤。</p><h2 id="权限定义实体-syspermission" tabindex="-1">权限定义实体：<code>SysPermission</code> <a class="header-anchor" href="#权限定义实体-syspermission" aria-label="Permalink to &quot;权限定义实体：\`SysPermission\`&quot;">​</a></h2><p>权限码只是字符串标签，落库的权限定义是 <code>SysPermission</code>。它遵循标准 RBAC &quot;权限 = 资源 + 操作&quot;的原子建模：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>PermissionCode</code></td><td>权限码（<code>TenantId + PermissionCode</code> 租户内唯一），推荐三段式</td></tr><tr><td><code>ModuleCode</code></td><td>模块段（如 <code>saas</code>），支持三段式权限码</td></tr><tr><td><code>PermissionType</code></td><td><code>ResourceBased</code>（绑定 <code>ResourceId</code>+<code>OperationId</code>）/ <code>Functional</code>（仅凭码）/ <code>DataScope</code></td></tr><tr><td><code>ResourceId</code> / <code>OperationId</code></td><td>关联 <code>SysResource</code> / <code>SysOperation</code>（<code>ResourceBased</code> 时必填）</td></tr><tr><td><code>IsRequireAudit</code></td><td>该权限操作是否强制写 <code>SysDiffLog</code></td></tr><tr><td><code>Priority</code></td><td>数字越大越高；<strong>仅</strong>用于同级别 Grant/Deny 排序，不参与 Grant vs Deny 跨级覆盖（Deny 始终优先）</td></tr><tr><td><code>Status</code></td><td><code>Enabled</code> / <code>Disabled</code></td></tr></tbody></table><p><code>TenantId = 0</code> 的权限是<strong>平台级全局权限</strong>（派生属性 <code>IsGlobal=true</code>），作为模板供订阅版本（<code>SysTenantEditionPermission</code>）引用；合并查询用 <code>WHERE TenantId IN (0, 当前租户)</code>。删除权限仅软删，且删除前须校验无角色/用户仍授权、无菜单引用、无版本引用。</p><h2 id="rbac-角色驱动" tabindex="-1">RBAC：角色驱动 <a class="header-anchor" href="#rbac-角色驱动" aria-label="Permalink to &quot;RBAC：角色驱动&quot;">​</a></h2><p>用户通过<strong>角色</strong>获得权限码集合。角色是权限分配单元：</p><ul><li><code>SysRole</code>：承载一组权限，通过 <code>SysUserRole</code> 赋给用户。<code>RoleType</code> 分 <code>System</code>（平台预置，必须 <code>TenantId=0</code>）/ <code>Business</code> / <code>Custom</code>（租户自建，不可全局化）。预置模板如 Owner/Admin/Manager/Member/Viewer/External。</li><li><code>SysRolePermission</code>：角色↔权限绑定，字段含 <code>PermissionAction</code>（<code>Grant</code>/<code>Deny</code>）、生效/失效时间（<code>EffectiveTime</code>/<code>ExpirationTime</code>）、<code>GrantReason</code>（关联审批单/工单，审计追溯）。</li><li><code>SysUserRole</code>：用户↔角色绑定（用户&quot;持有&quot;角色）。</li></ul><h3 id="角色层级继承-闭包表" tabindex="-1">角色层级继承（闭包表） <a class="header-anchor" href="#角色层级继承-闭包表" aria-label="Permalink to &quot;角色层级继承（闭包表）&quot;">​</a></h3><p>角色支持层级继承，用<strong>闭包表</strong> <code>SysRoleHierarchy</code> 存储所有继承关系（含直接与传递）：</p><ul><li>每条记录是 <code>(AncestorId, DescendantId, Depth, Path)</code>；<code>Depth=0</code> 是自关联，<code>Depth=1</code> 直接继承，<code>Depth=n</code> 为 n 级间接继承，<code>Path</code> 形如 <code>1/3/5</code>。</li><li>核心不变式：若 <code>A→B</code> 且 <code>B→C</code> 存在，则 <code>A→C</code> 也必须存在。表<strong>不设</strong> <code>Status</code>/<code>IsDeleted</code>——单条停用会破坏传递闭包一致性，变更时整体重建受影响路径，硬删。</li><li>继承语义：后代自动获得祖先的所有 <strong>Grant</strong> 权限，可被后代自己的 <code>SysRolePermission.Deny</code> 覆盖；<strong><code>DataScope</code> 不继承</strong>（每个角色独立定义数据范围）；SSD/DSD 约束检查须展开继承链。</li><li>写入时服务层做<strong>环路检测</strong>（禁止 <code>A→B→A</code>）。DAG 多路径时 <code>(A,C)</code> 的 <code>Depth</code> 取最短路径。</li></ul><h3 id="用户直授与合并优先级" tabindex="-1">用户直授与合并优先级 <a class="header-anchor" href="#用户直授与合并优先级" aria-label="Permalink to &quot;用户直授与合并优先级&quot;">​</a></h3><p>除角色外，用户可被<strong>直接授权</strong> <code>SysUserPermission</code>（<code>Grant</code>/<code>Deny</code>），用于临时提权、特殊例外、紧急收回。多来源冲突按 <strong>deny-overrides + 优先级</strong> 合并，优先级从高到低：</p><table tabindex="0"><thead><tr><th>级别</th><th>来源</th><th>语义</th></tr></thead><tbody><tr><td>1（最高）</td><td>用户直授 <code>Deny</code></td><td>最终拒绝，任何角色 Grant 都不能覆盖</td></tr><tr><td>2</td><td>用户直授 <code>Grant</code></td><td>最终授予，即使所有角色 Deny</td></tr><tr><td>3</td><td>角色级 <code>Deny</code></td><td>仅作用于当前角色的继承链，不影响其他独立角色</td></tr><tr><td>4</td><td>角色级 <code>Grant</code></td><td>当前角色的权限授予</td></tr></tbody></table><p>角色级 Deny 的作用域是关键细节：若角色 B 继承 A、B 对权限 P 标 Deny，则<strong>经 B</strong> 拿不到 P；但用户若同时直接持有 A，仍能<strong>经 A</strong> 拿到 P。</p><h2 id="数据范围-data-scope" tabindex="-1">数据范围（Data Scope） <a class="header-anchor" href="#数据范围-data-scope" aria-label="Permalink to &quot;数据范围（Data Scope）&quot;">​</a></h2><p>同一个权限码，能看到的数据行随<strong>数据范围</strong>收窄。范围档位由 <code>SysRole.DataScope</code>（枚举 <code>DataPermissionScope</code>）承载：</p><table tabindex="0"><thead><tr><th>枚举值</th><th>含义</th></tr></thead><tbody><tr><td><code>SelfOnly</code></td><td>仅本人创建的数据</td></tr><tr><td><code>DepartmentOnly</code></td><td>用户当前租户上下文下全部有效部门归属，仅限这些部门</td></tr><tr><td><code>DepartmentAndChildren</code></td><td>上述部门 + 其所有下级部门</td></tr><tr><td><code>All</code></td><td>全部数据</td></tr><tr><td><code>Custom</code></td><td>由 <code>SysRoleDataScope</code> 明确枚举可访问的部门列表</td></tr></tbody></table><blockquote><p><strong>重要</strong>：该枚举<strong>不承诺&quot;数值越大范围越广&quot;</strong>（<code>Custom=99</code>）。多角色合并必须按显式语义处理：任一角色 <code>All</code> → 全部；<code>DepartmentOnly</code>/<code>DepartmentAndChildren</code> → 求部门归属并集；<code>Custom</code> → 与其它范围并集叠加；仅 <code>SelfOnly</code> 才只返回本人数据。禁止用数值大小做合并判断。</p></blockquote><p>自定义范围有两张对称的明细表，仅在档位为 <code>Custom</code> 时枚举可见部门：</p><ul><li><code>SysRoleDataScope</code>：服务 <code>SysRole.DataScope=Custom</code>。字段 <code>RoleId</code>+<code>DepartmentId</code>，<code>IncludeChildren=true</code> 时服务层配合 <code>SysDepartmentHierarchy</code> 展开所有后代部门（新增子部门自动纳入）。</li><li><code>SysUserDataScope</code>：服务用户级覆盖 <code>SysUser.DataScopeOverride=Custom</code>，纯部门明细。<strong>用户级覆盖优先级高于角色级</strong>：当用户 <code>DataScopeOverride</code> 非空时，忽略角色的 <code>DataScope</code>。</li></ul><p>数据范围在<strong>查询层</strong>生效：解析出可见部门集后生成 <code>WHERE dept_id IN (...)</code>，与权限码组合决定&quot;能对哪些行做这个动作&quot;。</p><h2 id="字段级脱敏-fls" tabindex="-1">字段级脱敏（FLS） <a class="header-anchor" href="#字段级脱敏-fls" aria-label="Permalink to &quot;字段级脱敏（FLS）&quot;">​</a></h2><p>即使有权读取某条记录，<strong>敏感字段</strong>仍可能被脱敏或禁读。策略实体 <code>SysFieldLevelSecurity</code> 控制某个资源特定字段的可读/可编辑与脱敏形式：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>TargetType</code> / <code>TargetId</code></td><td>策略绑定到 <code>Role</code> / <code>User</code> / <code>Permission</code> / <code>Department</code>（<code>FieldSecurityTargetType</code>）</td></tr><tr><td><code>ResourceId</code> / <code>FieldName</code></td><td>受控资源与字段名（区分大小写，对应实体属性名）</td></tr><tr><td><code>IsReadable</code></td><td>是否可读；<code>false</code> 时按 <code>MaskStrategy</code> 返回</td></tr><tr><td><code>IsEditable</code></td><td>是否可编辑；<code>false</code> 时前端只读、后端写操作拒绝</td></tr><tr><td><code>MaskStrategy</code></td><td>脱敏策略（见下表）</td></tr><tr><td><code>MaskPattern</code></td><td>配合策略的规则串（JSON/表达式）</td></tr><tr><td><code>Priority</code></td><td>数字越大越高，用于冲突合并覆盖低优先级（如用户级白名单覆盖角色级限制）</td></tr></tbody></table><p>脱敏策略 <code>FieldMaskStrategy</code>：<code>None</code>（原值）/ <code>Hidden</code>（隐藏或返回 null）/ <code>FullMask</code>（全星号）/ <code>PartialMask</code>（保留首尾，如 <code>138****1234</code>）/ <code>Hash</code>（不可逆）/ <code>Redact</code>（固定替换如 <code>[已脱敏]</code>）/ <code>Custom</code>。</p><p><strong>可见性三段语义</strong>（RBAC/ABAC 判定之后生效）：</p><ul><li><code>IsReadable=true</code> + <code>MaskStrategy=None</code> → 可读原文</li><li><code>IsReadable=true</code> + <code>MaskStrategy!=None</code> → 可读脱敏值（如客服看手机号 <code>138****1234</code>）</li><li><code>IsReadable=false</code> → 不可读，按策略返回脱敏/隐藏结果</li></ul><p><strong>冲突合并</strong>采用 deny-overrides + 优先级：命中的多条规则里，任一 <code>IsReadable=false</code> → 最终不可读，任一 <code>IsEditable=false</code> → 最终不可编辑，取最严脱敏；<code>Priority</code> 更高的规则可覆盖低优先级（白名单放行场景）。</p><h3 id="服务端落地-读脱敏-写校验-排序-过滤门控" tabindex="-1">服务端落地：读脱敏 + 写校验 + 排序/过滤门控 <a class="header-anchor" href="#服务端落地-读脱敏-写校验-排序-过滤门控" aria-label="Permalink to &quot;服务端落地：读脱敏 + 写校验 + 排序/过滤门控&quot;">​</a></h3><p>FLS 由 <code>IFieldSecurityService</code> 在服务端强制落地，<strong>不依赖前端</strong>：</p><ul><li><code>ResolveAsync(resourceCode)</code>：解析当前用户在某资源上的有效规则（合并 deny-overrides），得到 <code>EffectiveFieldRule</code> 字典。</li><li><code>ApplyAsync(resourceCode, item/items)</code>：对返回 DTO/集合<strong>反射就地脱敏</strong>。列表、详情、导出都调用它。</li><li><code>EnsureEditableAsync</code> / <code>EnsureUpdatableAsync</code>：写路径校验——命中不可编辑字段被实际修改则抛异常。</li><li><code>GuardSortsAsync</code> / <code>GuardFiltersAsync</code>：<strong>推断攻击防护</strong>——就地剔除当前用户&quot;不可读或已脱敏&quot;字段的排序键与过滤条件。否则用户可按受保护字段排序/过滤，从结果顺序反推被脱敏的真实值。字段名大小写不敏感匹配，无显式规则默认放行。</li></ul><p>前端另有 <code>MyFieldSecurityAppService.GetMineAsync(resourceCode)</code> 下发&quot;可读/可编辑/脱敏&quot;信息，供表单据 <code>IsEditable</code> 置只读、展示脱敏标识——但<strong>脱敏值本身已由服务端在响应里落地</strong>，前端仅做体验优化。</p><p><strong>导出一致脱敏</strong>：后台导出走 <code>ExportExecutor</code>，它在后台线程先按任务发起人重建 <code>CurrentTenant</code> + <code>CurrentPrincipal</code>，再调用既有 QueryService，使<strong>数据范围与字段脱敏原样生效</strong>，并显式 <code>IPermissionChecker</code> 补齐进程内不触发 <code>[PermissionAuthorize]</code> 的缺口。因此导出与在线列表看到的脱敏结果一致。</p><h2 id="abac-属性驱动的约束" tabindex="-1">ABAC：属性驱动的约束 <a class="header-anchor" href="#abac-属性驱动的约束" aria-label="Permalink to &quot;ABAC：属性驱动的约束&quot;">​</a></h2><p>在 RBAC 之上，ABAC 用<strong>属性与规则</strong>做更细的运行时约束。两套机制并存：</p><h3 id="权限条件-syspermissioncondition-轻量-abac" tabindex="-1">权限条件 <code>SysPermissionCondition</code>（轻量 ABAC） <a class="header-anchor" href="#权限条件-syspermissioncondition-轻量-abac" aria-label="Permalink to &quot;权限条件 \`SysPermissionCondition\`（轻量 ABAC）&quot;">​</a></h3><p>为某条角色权限或用户直授权限附加属性条件，与授权绑定一一挂钩：</p><ul><li>排他约束：<code>RolePermissionId</code> 与 <code>UserPermissionId</code> <strong>恰好一个非空</strong>（服务层 XOR 校验，建议库层补 CHECK 约束）。</li><li>组合逻辑：同一 <code>ConditionGroup</code> 内条件为 <strong>AND</strong>，不同组之间为 <strong>OR</strong>（单权限最多 5 组、每组最多 10 条）。</li><li>属性命名走 XACML 风格命名空间：<code>subject.*</code> / <code>resource.*</code> / <code>environment.*</code>。建模层面的常用属性如 <code>subject.department</code>、<code>resource.status</code>、<code>resource.owner</code>、<code>resource.amount</code>、<code>environment.hour</code>、<code>environment.ip</code>、<code>environment.location</code>。</li><li><code>Operator</code>（<code>ConditionOperator</code>）覆盖 <code>Equals</code>/<code>NotEquals</code>/比较/<code>Contains</code>/<code>In</code>/<code>Between</code>/<code>StartsWith</code>/<code>EndsWith</code>/<code>IsNull</code> 等，<code>IsNegated</code> 可整体取反；<code>ValueType</code> 固定值解析类型防漂移。</li></ul><p>条件建模示例（存储层语义）：</p><table tabindex="0"><thead><tr><th>场景</th><th>属性</th><th>操作符</th><th>值</th></tr></thead><tbody><tr><td>仅工作时间</td><td><code>environment.hour</code></td><td><code>Between</code></td><td><code>9,18</code></td></tr><tr><td>仅内网</td><td><code>environment.ip</code></td><td><code>StartsWith</code></td><td><code>192.168.</code></td></tr><tr><td>只能操作草稿</td><td><code>resource.status</code></td><td><code>Equals</code></td><td><code>draft</code></td></tr><tr><td>限额操作</td><td><code>resource.amount</code></td><td><code>LessThan</code></td><td><code>10000</code></td></tr></tbody></table><blockquote><p><strong>建模 vs. 运行时</strong>：上述属性/操作符描述的是 <code>SysPermissionCondition</code> 的<strong>存储表达能力</strong>。运行时由框架 <code>IAbacAttributeCollector</code> 收集 <code>subject./resource./environment.</code> 属性、<code>IAbacEvaluator</code> 评估，混合策略里 ABAC 段以策略码触发（如 <code>same_tenant</code>/<code>self_only</code> 及比较式）。框架默认评估器对 <code>subject.*</code>/<code>resource.*</code> 的同租户、仅本人、字段比较有内建支持；时间窗/IP 这类 <code>environment.*</code> 条件的真实取值需应用侧属性收集器提供，未接入收集器的属性不会自动生效——落地前请以仓库为准确认对应属性已被收集。</p></blockquote><h3 id="约束规则-sysconstraintrule-sysconstraintruleitem" tabindex="-1">约束规则 <code>SysConstraintRule</code>（+ <code>SysConstraintRuleItem</code>） <a class="header-anchor" href="#约束规则-sysconstraintrule-sysconstraintruleitem" aria-label="Permalink to &quot;约束规则 \`SysConstraintRule\`（+ \`SysConstraintRuleItem\`）&quot;">​</a></h3><p>面向角色/权限组合的 RBAC 约束（职责分离等），规则元数据在主表、涉及的角色/权限/用户 ID 拆到 <code>SysConstraintRuleItem</code> 独立成行（保引用完整性）：</p><ul><li><code>ConstraintType</code>：<code>SSD</code>（静态职责分离，不能同时<strong>持有</strong>互斥角色）/ <code>DSD</code>（动态职责分离，同一<strong>会话</strong>不能同时激活互斥角色）/ <code>MutualExclusion</code> / <code>Cardinality</code>（基数）/ <code>Prerequisite</code>（先决条件）/ <code>Temporal</code>（时间）/ <code>Location</code>（位置）/ <code>Custom</code>。</li><li><code>ViolationAction</code>：违规处理 <code>Deny</code> / <code>Warning</code> / <code>Log</code> / <code>RequireApproval</code>。</li><li>非 ID 类参数（时间窗、最大数量等）以 JSON 存 <code>Parameters</code>；有效性由 <code>Status=Enabled</code> 且当前时间落在 <code>EffectiveTime~ExpirationTime</code> 共同决定。</li><li><strong>约束检查必须展开角色继承链</strong>：若 Item 指向角色 A，任何继承 A 的后代角色都视为等效目标（经 <code>SysRoleHierarchy</code> 展开）。<code>ConstraintGroup</code> 标识互斥集合（先决条件约束中 0=必备项、1=目标项）。</li></ul><h2 id="会话角色激活-动态职责分离" tabindex="-1">会话角色激活（动态职责分离） <a class="header-anchor" href="#会话角色激活-动态职责分离" aria-label="Permalink to &quot;会话角色激活（动态职责分离）&quot;">​</a></h2><p><code>SysUserRole</code> 是&quot;持有&quot;，<code>SysSessionRole</code> 是&quot;激活&quot;：用户可能持有多个角色，但一次会话只激活其中一个子集，用于动态职责分离与最小权限。</p><ul><li><code>SessionId</code>（关联 <code>SysUserSession</code> 主键）+ <code>RoleId</code> 唯一；<code>Status</code>（<code>SessionRoleStatus</code>）为 <code>Active</code>/<code>Inactive</code>/<code>Expired</code>，配合 <code>ActivatedTime</code>/<code>DeactivatedTime</code>/<code>ExpirationTime</code> 记录生命周期。</li><li><strong>激活前置校验</strong>：该用户确实持有此角色（<code>SysUserRole</code> 存在且未过期），且激活通过 DSD 约束检查（<code>SysConstraintRule</code> 中 <code>ConstraintType=DSD</code>）。</li><li>典型用法：敏感操作前临时激活特权角色，完成后立即停用；凌晨扫描失效已过期的会话角色。</li></ul><p>设计意图是让一次会话只以其激活的角色子集办事，从而即便持有互斥角色也不会在同一会话同时生效；DSD 约束在<strong>激活时</strong>校验拦截。持久的角色持有关系仍记在 <code>SysUserRole</code>，会话激活是叠加在其上的运行期约束。</p><h2 id="申请、审批、委托与留痕" tabindex="-1">申请、审批、委托与留痕 <a class="header-anchor" href="#申请、审批、委托与留痕" aria-label="Permalink to &quot;申请、审批、委托与留痕&quot;">​</a></h2><ul><li><strong>权限申请</strong> <code>SysPermissionRequest</code>：用户申请权限/角色 → 关联 <code>SysReview</code> 审批流 → 审批通过后由服务层<strong>自动</strong>写入 <code>SysUserRole</code>/<code>SysUserPermission</code> 完成授权。状态 <code>PermissionRequestStatus</code>：<code>Pending</code>/<code>Approved</code>/<code>Rejected</code>/<code>Withdrawn</code>/<code>Expired</code>；可带期望生效/失效时间。</li><li><strong>权限委托</strong> <code>SysPermissionDelegation</code>：建模&quot;委托人 → 被委托人 → 权限范围 → 时间窗口&quot;（如经理出差把审批权委托给副手）。<code>PermissionId</code>/<code>RoleId</code> 可空（空=委托全部）；<code>ExpirationTime</code> <strong>必填</strong>（委托必须有截止）；生效需 <code>DelegationStatus=Active</code>（<code>DelegationStatus</code>：<code>Pending</code>/<code>Active</code>/<code>Expired</code>/<code>Revoked</code>）且当前时间在窗口内。撤销走 <code>Revoked</code>（软删）。</li><li><strong>变更留痕</strong> <code>SysPermissionChangeLog</code>：结构化记录&quot;谁在什么时候给谁授予/撤销了什么权限&quot;，是 RBAC 合规审计的核心证据。<strong>只追加，禁止更新和删除</strong>，按月分表（<code>SplitTable</code>），携带 <code>OperatorUserId</code>/<code>TargetUserId</code>/<code>TargetRoleId</code>/<code>PermissionId</code>/<code>ChangeType</code>/<code>OperationIp</code>/<code>TraceId</code>。<code>ChangeType</code>（<code>PermissionChangeType</code>）区分角色/用户的授予、撤销、拒绝、分配/移除角色等。与 <code>SysDiffLog</code>（通用实体字段变更）职责分离——本表专注权限授予/撤销的业务语义。</li></ul><h2 id="版本-edition-门控" tabindex="-1">版本（Edition）门控 <a class="header-anchor" href="#版本-edition-门控" aria-label="Permalink to &quot;版本（Edition）门控&quot;">​</a></h2><p>多租户下不同订阅版本开放不同权限。<code>SysTenantEditionPermission</code> 是 Plan-gating 核心：定义每个版本（<code>Edition</code>）向租户开放的<strong>权限白名单</strong>。</p><ul><li><code>EditionId</code> + <code>PermissionId</code> 唯一，<code>PermissionId</code> 通常指向 <code>TenantId=0</code> 的全局权限（<code>IsGlobal=true</code>），非全局权限不应被版本门控。</li><li>租户可用权限集 = <code>SysTenant.EditionId</code> → 此表 → 可用 <code>PermissionId</code> 集；租户管理员分配角色/用户权限时须在此集合内选择。</li><li>版本升级（如 Basic → Pro）增量写入新增权限；开通版本时一站式创建 Owner 角色并按白名单批量授权。</li></ul><p>版本门控有<strong>运行时</strong>与<strong>持久回收</strong>两层，互为兜底：</p><p><strong>运行时门控</strong>：构建授权快照时，<code>ApplyEditionGatingAsync</code> 把用户有效权限集与当前版本白名单<strong>求交</strong>，超出白名单的权限即使 DB 里仍有绑定也不进入本次生效集。跳过门控的情形：超管通配 <code>*</code>、平台运维（无租户上下文）、无版本绑定、白名单为空。版本权限变更会失效版本门控缓存，下次判定即按新白名单收窄。</p><p><strong>降级自动回收越权授权</strong>：租户版本变更时（<code>TenantDomainService</code> 检测到 <code>EditionId</code> 变化），调用 <code>TenantProvisionDomainService.ReconcileTenantAuthorizationWithEditionAsync</code>，按新版本白名单<strong>回收超出范围的存量角色/用户直授权限行</strong>。关键实现细节：</p><ul><li>白名单为<strong>空视为门控未启用</strong>（与运行时鉴权语义一致），不做回收，避免误清。</li><li>仅处理该租户<strong>自有</strong>绑定行（<code>TenantId=本租户</code>）；全局行（<code>TenantId=0</code>）属平台运维资产，不在回收范围。</li></ul><h2 id="判定链" tabindex="-1">判定链 <a class="header-anchor" href="#判定链" aria-label="Permalink to &quot;判定链&quot;">​</a></h2><p>一次访问要逐层穿过下面的关卡，层层收紧、默认从严。请求先经框架中间件管道 <code>TraceId → 请求文化 → 认证 → 租户解析 → 授权 → 端点</code>，授权在其中由 <code>[PermissionAuthorize(...)]</code> 触发：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求进来</span></span>
<span class="line"><span>  → 认证：你是谁（从主体声明解析 userId；解析不到直接拒绝）</span></span>
<span class="line"><span>  → 租户解析：落到哪个租户上下文（字段级隔离，全局数据 TenantId=0）</span></span>
<span class="line"><span>  → 授权(RBAC)：IPermissionChecker 实时校验权限码（查授权快照）</span></span>
<span class="line"><span>        · deny-overrides：用户 Deny &gt; 用户 Grant &gt; 角色 Deny &gt; 角色 Grant</span></span>
<span class="line"><span>        · 角色权限经 SysRoleHierarchy 展开继承链（祖先 Grant，后代 Deny 覆盖）</span></span>
<span class="line"><span>        · 委托权限（SysPermissionDelegation）并入快照，再统一被用户 Deny 收窄</span></span>
<span class="line"><span>        · 版本白名单求交（ApplyEditionGatingAsync）</span></span>
<span class="line"><span>        · super_admin 角色 → 全部启用权限 + 字面 * 通配放行</span></span>
<span class="line"><span>  → 授权(ABAC)：SysPermissionCondition / SysConstraintRule 属性约束</span></span>
<span class="line"><span>        · 收集 subject./resource./environment. 属性 → 评估器按策略码判定</span></span>
<span class="line"><span>          （同租户/仅本人/比较式内建；时间窗/IP 依赖应用侧属性收集器）</span></span>
<span class="line"><span>  → 数据范围：DataPermissionScope 解析可见部门集 → WHERE dept_id IN (...)</span></span>
<span class="line"><span>  → 字段脱敏：FLS 按 deny-overrides 就地脱敏（读/导出一致），并门控排序/过滤字段</span></span></code></pre></div><p>判定采用框架的<strong>混合策略</strong>：<code>[PermissionAuthorize]</code> 把&quot;权限码 + ABAC 策略码&quot;编码进一个 ASP.NET Core 策略名，由 <code>HybridPermissionAuthorizationHandler</code> 依次执行&quot;权限码实时校验 → ABAC 属性评估&quot;。</p><blockquote><p><strong>实时校验，非信任令牌</strong>：授权处理器<strong>不信任 JWT 里冻结的权限声明</strong>，每次都走 <code>IPermissionChecker</code> 查当前授权快照。因此权限授予/回收、用户禁用、会话注销<strong>即时生效</strong>，无需等令牌过期。凡是影响授权的写操作（权限增删改、角色/用户授权变更）都会精准失效授权快照缓存。</p></blockquote><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./architecture">系统架构</a>：权限判定在请求管道中的位置</li><li><a href="./multi-tenancy">多租户</a>：租户隔离与版本门控全貌</li><li><a href="./audit-log">审计日志</a>：<code>SysDiffLog</code> / <code>SysPermissionChangeLog</code> 等留痕</li><li><a href="./../framework/packages/authorization">框架 · 授权模块</a>：底层 RBAC / Policy / ABAC 与混合策略实现</li><li><a href="./../framework/packages/authentication">框架 · 认证模块</a>：JWT / OAuth2 / 2FA 身份声明</li></ul>`,77)])])}const h=o(s,[["render",a]]);export{g as __pageData,h as default};
